svg.script:

console.clear();
console.log('═══════════════════════════════════════');
console.log('🌍 AI.PLANET.COM - BLOB URL VIEWER');
console.log('═══════════════════════════════════════');
console.log('✅ SVG loaded successfully');
console.log('📍 Origin:', window.location.origin);
console.log('📍 URL:', window.location.href);
console.log('📌 Mode: Blob URL (same origin)');

// Track iframe loading
var iframeLoadStatus = {
    loaded: false,
    attempts: 0,
    startTime: Date.now()
};

function checkIframe() {
    var iframe = document.getElementById('planetIframe');
    if (!iframe) {
        console.warn('⚠️ Iframe not found');
        return;
    }

    iframeLoadStatus.attempts++;

    try {
        // Try to access iframe content
        var doc = iframe.contentDocument || iframe.contentWindow?.document;

        if (doc && doc.readyState === 'complete') {
            if (!iframeLoadStatus.loaded) {
                iframeLoadStatus.loaded = true;
                var loadTime = (Date.now() - iframeLoadStatus.startTime) / 1000;
                console.log('✅ IFRAME LOADED SUCCESSFULLY!');
                console.log('  📍 Time to load:', loadTime.toFixed(2) + 's');
                console.log('  📍 Title:', doc.title || 'No title');
                console.log('  📍 Content length:', doc.body?.innerHTML?.length || 0);
                console.log('  📍 readyState:', doc.readyState);

                // Update status display
                updateStatus('✅ Connected', '#4CAF50');
            }
        } else if (doc) {
            console.log('⏳ Iframe loading... (readyState:', doc.readyState || 'unknown', ')');
        }
    } catch(e) {
        // CORS or other access issues
        if (!iframeLoadStatus.loaded) {
            // If we can detect that it loaded despite CORS
            try {
                // Check if iframe has a src and is not about:blank
                if (iframe.src && iframe.src !== 'about:blank' && iframe.src.startsWith('https://')) {
                    console.log('✅ Iframe appears to be loaded (CORS prevents content access)');
                    console.log('  📍 This is normal for cross-origin iframes');
                    console.log('  📌 Content is loaded but cannot be inspected');
                    iframeLoadStatus.loaded = true;
                    updateStatus('✅ Connected (CORS)', '#4CAF50');
                }
            } catch(e2) {
                // Ignore
            }
        }
    }
}

function updateStatus(text, color) {
    try {
        var statusText = document.querySelector('.info-text');
        if (statusText) {
            // Find the status part
            var parts = statusText.textContent.split('•');
            if (parts.length >= 2) {
                statusText.textContent = 'Status: ' + text + '  •' + parts.slice(1).join('•');
            }
        }
    } catch(e) {
        // Ignore
    }
}

// Monitor iframe loading
var checkInterval = setInterval(checkIframe, 500);

// Also check on window load
window.addEventListener('load', function() {
    console.log('📌 Window load event fired');
    setTimeout(checkIframe, 500);
});

// Stop checking after 30 seconds
setTimeout(function() {
    clearInterval(checkInterval);
    if (!iframeLoadStatus.loaded) {
        console.log('⏱️ Timeout: Iframe may still be loading or blocked');
        console.log('  📌 Check if authentication is required');
        console.log('  📌 Check if iframe is visible');
    }
    console.log('\n═══════════════════════════════════════');
    console.log('📊 FINAL STATUS:');
    console.log('  📍 Iframe loaded:', iframeLoadStatus.loaded ? '✅ YES' : '❌ NO');
    console.log('  📍 Attempts:', iframeLoadStatus.attempts);
    console.log('  📍 Total time:', ((Date.now() - iframeLoadStatus.startTime) / 1000).toFixed(2) + 's');

    // Check if iframe exists
    var iframe = document.getElementById('planetIframe');
    if (iframe) {
        console.log('  📍 Iframe src:', iframe.src);
        console.log('  📍 Iframe style:', iframe.style.cssText);
    }
    console.log('═══════════════════════════════════════');
}, 30000);

// Add keyboard shortcuts
document.addEventListener('keydown', function(e) {
    if (e.key === 'r' && (e.ctrlKey || e.metaKey)) {
        e.preventDefault();
        console.log('🔄 Reloading iframe...');
        var iframe = document.getElementById('planetIframe');
        if (iframe) {
            iframe.src = iframe.src;
        }
    }
    if (e.key === 'f' && (e.ctrlKey || e.metaKey)) {
        e.preventDefault();
        console.log('🔍 Toggle fullscreen...');
        var iframe = document.getElementById('planetIframe');
        if (iframe && iframe.requestFullscreen) {
            iframe.requestFullscreen();
        }
    }
});

console.log('\n📌 Keyboard shortcuts:');
console.log('  Ctrl+R  - Reload iframe');
console.log('  Ctrl+F  - Toggle fullscreen');
console.log('═══════════════════════════════════════');
